import pull from "../../../../../../../../../../../subject_repositories/pull-stream/pull.js"

describe("pull", () => {
  it("should handle object streams without throwing when passed as through streams", () => {
    const source = (end: any, cb: Function) => { cb(true) }

    let sinkCalled = false
    const objectStream = {
      sink: (read: any) => { sinkCalled = true },
      source: (end: any, cb: Function) => { cb(true) }
    }

    expect(() => {
      pull(source, objectStream)
    }).not.toThrow()

    expect(sinkCalled).toBe(true)
  })
})
